INSERT INTO `announcement` (`admin_id`, `title`, `content`, `is_top`, `create_time`) VALUES
(1, '欢迎使用高校学生考证服务系统', '亲爱的同学们：\n\n高校学生考证服务系统正式上线了！本系统涵盖考公、考研、英语四六级、雅思、托福、计算机等级等热门考试，为大家提供：\n\n1. 考试信息查询 - 及时获取考试时间、报名入口等信息\n2. 备考经验交流 - 通过帖子分享和讨论备考心得\n3. 问答互助 - 遇到问题随时提问，学长学姐帮你解答\n\n希望本系统能助力大家顺利通过考试，祝各位前程似锦！\n\n系统管理员\n2026年4月', 1, '2026-04-01 09:00:00'),
(1, '2026年上半年考试日历提醒', '各位同学请注意以下重要考试时间节点：\n\n【3月】\n- 3月28日-30日：全国计算机等级考试（NCRE）\n- 3月22日：多省公务员联考笔试\n\n【4月】\n- 雅思/托福考试（多场次，请提前报名）\n\n【6月】\n- 6月14日：大学英语四六级考试（CET-4/CET-6）\n\n【10月】\n- 10月5日-25日：2027年考研网上报名\n\n【12月】\n- 12月7日-8日：2026年国家公务员考试笔试\n- 12月中旬：大学英语四六级考试\n- 12月21日-22日：2027年考研初试\n\n请同学们合理规划时间，提前做好备考准备！', 1, '2026-04-05 10:00:00'),
(1, '关于规范发帖的通知', '为维护良好的交流环境，请各位用户遵守以下规范：\n\n1. 发帖内容须与考证备考相关\n2. 禁止发布广告、推销等无关内容\n3. 禁止发布违法违规信息\n4. 尊重他人，文明交流，禁止人身攻击\n5. 禁止发布虚假考试信息\n\n违规帖子将被删除，严重者将被禁用账号。\n\n感谢大家的配合！', 0, '2026-04-10 14:00:00'),
(1, 'CET-4/CET-6报名即将开始', '同学们注意啦！\n\n2026年上半年大学英语四六级考试报名即将开始：\n\n报名时间：2026年3月下旬至4月上旬\n考试时间：2026年6月14日\n\n四级：上午9:00-11:20\n六级：下午15:00-17:25\n\n报名方式：登录CET报名网站 cet-bm.neea.edu.cn\n\n请还未通过四六级的同学抓紧时间报名，不要错过报名截止日期！\n\n预祝大家取得好成绩！', 0, '2026-04-15 08:30:00'),
(1, '系统维护通知', '各位用户：\n\n为提升系统性能和用户体验，系统将于2026年4月25日凌晨2:00-6:00进行维护升级。\n\n维护期间系统将暂时无法访问，请大家提前做好安排。\n\n维护内容：\n- 服务器性能优化\n- 新增考试模块功能\n- 修复已知问题\n\n给您带来的不便敬请谅解！', 0, '2026-04-18 16:00:00');
